// DMA 循环缓冲区架构示意
//
// 内存层：uint8_t rx_buf[1024]  // 2^10，mask = 0x3FF
// DMA层：  DMA2_Stream3, Channel3
//          USART2_RX → 内存，循环模式，TC 中断
// 处理层：  中断标记 + 任务消费

// 缓冲区状态（volatile，ISR 和任务共享）
volatile struct dma_buf_status {
    uint16_t dma_tail;   // DMA 写入位置（ISR 更新）
    uint16_t cpu_head;   // CPU 读取位置（任务更新）
    uint8_t  new_data;   // 有新数据标志
} buf __attribute__((section(".dma_buf")));

// ISR：DMA 传输完成时调用
void DMA2_Stream3_IRQHandler(void) {
    DMA2->HISR |= DMA_HISR_TCIF3;  // 清除 TC 标志
    buf.dma_tail = DMA2_Stream3->NDTR;  // 反算写入位置
    buf.new_data = 1;
    // 立即退出，不做数据处理
}

// 任务消费入口
uint16_t buf_available(void) {
    uint16_t tail = buf.dma_tail;
    uint16_t head = buf.cpu_head;
    return (tail - head) & 0x3FF;
}

/* dma_uart_rx.c：USART3 + DMA 循环接收
 * 缓冲区：1024 字节，DMA + CPU 共享
 * 平台：STM32F4 系列，HAL 库
 * 时钟：HSE 8MHz, USART3 @115200bps
 */

/* 缓冲区定义：DMA 写入段，编译器不优化 */
ALIGN_32(static uint8_t rx_buffer[1024])
    __attribute__((section(".dma_rx_buf")));

/* 索引管理（ISR 和任务共享）*/
static volatile uint16_t dma_idx = 0;
static volatile uint16_t cpu_idx  = 0;
static volatile uint8_t  data_flag = 0;

/* 初始化 USART3 + DMA2 Stream1 */
void dma_uart_init(UART_HandleTypeDef *huart) {
    __HAL_UART_ENABLE_IT(huart, UART_IT_RXNE);
    /* 开启 DMA TC 中断，NVIC 优先级设为 3 */
    HAL_NVIC_SetPriority(DMA2_Stream1_IRQn, 3, 0);
    HAL_NVIC_EnableIRQ(DMA2_Stream1_IRQn);

    /* 开始 DMA 循环接收 */
    HAL_UARTEx_ReceiveTo_DMA_DMA_Suspend(huart,
        rx_buffer, 1024);
}

/* DMA 传输完成回调（在中上下文中调用）*/
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart,
                                 uint16_t size) {
    if (huart->Instance == USART3) {
        dma_idx = 1024 - HAL_DMA_GetResult(DMA2_Stream1);
        data_flag = 1;
    }
}

/* 获取可用字节数 */
uint16_t dma_uart_available(void) {
    uint16_t tail = dma_idx;
    uint16_t head = cpu_idx;
    return (tail - head) & 0x3FF;
}

/* 读取一个字节（返回 0 表示失败）*/
uint8_t dma_uart_read_byte(uint8_t *out) {
    if (dma_uart_available() == 0) return 0;
    *out = rx_buffer[cpu_idx & 0x3FF];
    cpu_idx++;
    return 1;
}

/* 陷阱 1 的防御性代码：缓冲区 75% 告警 */
uint16_t buf_available(void) {
    uint16_t tail = buf.dma_tail;
    uint16_t head = buf.cpu_head;
    uint16_t avail = (tail - head) & 0x3FF;

    if (avail > 768) {  /* 75% of 1024 */
        buf_overrun_cnt++;  /* 计数器 */
        /* 策略 1：丢旧保新
         * buf.cpu_head = buf.dma_tail - 256;
         */
        /* 策略 2：告警，暂停处理 */
        log_warning("DMA buf 75%% full!");
    }
    return avail;
}

/* 陷阱 3 的正确 NDTR 读取 */
void DMA2_Stream3_IRQHandler(void) {
    /* 先读 NDTR，再清标志 */
    uint16_t ndtr = DMA2_Stream3->NDTR;
    buf.dma_tail = 1024 - ndtr;
    DMA2->HISR |= DMA_HISR_TCIF3;  /* 写 1 清除 */
    buf.new_data = 1;
}

/* ❌ 重构前：轮询 + 中断混合，代码耦合严重 */
void uart_receive_loop(void) {
    uint8_t frame[256];
    uint16_t frame_len = 0;
    while (1) {
        while (HAL_UART_Receive(&huart3, &byte, 1, 10) == HAL_OK) {
            if (byte == 0xFF) {  /* 帧头 */
                frame_len = 0;
            } else if (frame_len < 255) {
                frame[frame_len++] = byte;
            }
            if (frame_len >= 4 && frame[0] == 0xFF) {
                process_frame(frame, frame_len);
                frame_len = 0;
            }
        }
        /* 如果 UART_Receive 超时，主循环卡住 */
        /* 115200bps 时 CPU 利用率约 35% */
    }
}

/* ✅ 重构后：DMA 搬运 + 接口抽象 */
/* 缓冲区管理接口（ADT）*/
void buf_init(uint8_t *buf, uint16_t size);
uint16_t buf_available(void);
uint8_t  buf_read(uint8_t *out);
void     buf_clear(void);

/* 主循环：只处理业务，不碰硬件 */
void app_main_loop(void) {
    uint8_t frame[256];
    uint16_t available = buf_available();
    if (available >= 4) {
        uint16_t i = 0;
        while (i < available && buf_read(&frame[i])) i++;
        parse_frame(frame, i);  /* 业务逻辑 */
    }
    /* CPU 利用率 < 1%（115200bps 持续接收）*/
}
